module.exports = async function (input) {
  const { source, data } = input.json;

  const inputHandlers = {
    telegram: (d) => ({
      text: d.message?.text || d.message?.caption || '',
      source: 'telegram',
      chatId: d.message?.chat.id,
      userId: d.message?.from.id,
      hasImage: !!d.message?.photo,
      hasVoice: !!d.message?.voice,
      raw: d
    }),

    discord: (d) => ({
      text: d.content || '',
      source: 'discord',
      channelId: d.channel_id,
      userId: d.author.id,
      attachments: d.attachments || [],
      raw: d
    }),

    web: (d) => ({
      text: d.query || d.text || '',
      source: 'web',
      sessionId: d.sessionId || `web_${Date.now()}`,
      timelineData: d.timelinePoints || [],
      voiceTranscript: d.voiceTranscript || null,
      customStyle: d.style || 'professional',
      raw: d
    })
  };

  const handler = inputHandlers[source] || inputHandlers.telegram;
  const processed = handler(data || input.json);

  // Language detection
  const langPatterns = {
    spanish: /\b(el|la|y|es|que|por)\b/gi,
    french: /\b(le|la|et|est|dans|pour)\b/gi,
    german: /\b(der|die|das|und|ist|für)\b/gi,
    italian: /\b(il|la|e|è|per|con)\b/gi
  };

  let detectedLang = 'english';
  for (const [lang, pattern] of Object.entries(langPatterns)) {
    if (processed.text.match(pattern)?.length > 2) {
      detectedLang = lang;
      break;
    }
  }

  // Complexity analysis
  const wordCount = processed.text.split(/\s+/).length;
  const hasDates = /\d{4}|\b(century|BC|AD)\b/i.test(processed.text);
  const hasNames = /\b([A-Z][a-z]+\s+[A-Z][a-z]+)\b/.test(processed.text);

  const complexity = wordCount > 50 ? 'high' : 
                     hasDates && hasNames ? 'medium' : 'low';

  return {
    ...processed,
    metadata: {
      timestamp: new Date().toISOString(),
      requestId: `codex_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`,
      processingTier: complexity === 'high' ? 'premium' : 'standard',
      language: detectedLang,
      complexity: complexity,
      estimatedChapters: complexity === 'high' ? 15 : 
                        complexity === 'medium' ? 10 : 5
    }
  };
};

module.exports = async function (input) {
  const { is_valid, refined_topic, metadata } = input.json;

  if (!is_valid) {
    return {
      abort: true,
      message: input.json.reply_to_user || "Topic not valid for history book generation."
    };
  }

  // Generate unique IDs
  const jobId = `job_${Date.now()}_${Math.random().toString(36).substr(2, 6)}`;
  const batchId = `batch_${Date.now()}_${Math.random().toString(36).substr(2, 6)}`;

  // Determine research depth
  const complexity = metadata?.complexity || 'medium';
  const researchAgents = {
    low: ['timeline_basic'],
    medium: ['timeline_detailed', 'key_figures'],
    high: ['timeline_detailed', 'key_figures', 'cultural_context', 'primary_sources']
  }[complexity];

  return {
    jobData: {
      id: jobId,
      batchId: batchId,
      topic: refined_topic,
      originalText: input.json.text,
      source: input.json.source,
      metadata: metadata,
      style: input.json.suggested_style || 'documentary',
      language: input.json.language || 'en',
      difficulty: input.json.estimated_difficulty || 'intermediate',
      researchAgents: researchAgents,
      status: 'research_initiated',
      createdAt: new Date().toISOString(),
      estimatedCompletion: new Date(Date.now() + 
        (complexity === 'high' ? 900000 : 
         complexity === 'medium' ? 600000 : 300000)).toISOString()
    },
    researchPlan: {
      topic: refined_topic,
      agents: researchAgents.map(agent => ({
        name: agent,
        prompt: getAgentPrompt(agent, refined_topic, metadata),
        model: complexity === 'high' ? 'gpt-4.1-mini' : 'gpt-3.5-turbo',
        outputFormat: 'json'
      })),
      mergeStrategy: 'timeline_first'
    }
  };
};

function getAgentPrompt(agent, topic, metadata) {
  const prompts = {
    timeline_basic: `Extract 5-10 key dates for: "${topic}". Format: {dates: [{year: "", event: "", importance: "low|medium|high"}]}`,
    timeline_detailed: `Create detailed timeline for: "${topic}" with 10-20 events including dates, locations, key people. Return as structured timeline.`,
    key_figures: `Identify 3-8 key figures in: "${topic}". For each: name, role, significance, visual_description.`,
    cultural_context: `Describe cultural/social context for: "${topic}". Include: fashion, technology, daily_life, beliefs.`,
    primary_sources: `Suggest 3-5 primary sources/quotes for: "${topic}". Include: source, quote, context.`
  };
  return prompts[agent] || `Research: ${topic}`;
}

module.exports = async function (input) {
  const chapters = input.json.chapters || [];
  const jobData = input.json.jobData;

  // Assign unique IDs to each chapter
  const enhancedChapters = chapters.map((chapter, index) => ({
    ...chapter,
    chapter_uuid: `ch_${Date.now()}_${index}_${Math.random().toString(36).substr(2, 4)}`,
    job_id: jobData.id,
    batch_id: jobData.batchId,
    style: jobData.style,
    language: jobData.language,
    image_status: 'pending',
    image_url: null,
    image_generation_attempts: 0
  }));

  // Log chapter count
  console.log(`Generated ${enhancedChapters.length} chapters`);

  return {
    jobData: jobData,
    chapters: enhancedChapters,
    summary: {
      totalChapters: enhancedChapters.length,
      dateRange: {
        start: enhancedChapters[0]?.date,
        end: enhancedChapters[enhancedChapters.length - 1]?.date
      },
      keyFigures: [...new Set(enhancedChapters.flatMap(ch => ch.key_figures))].filter(Boolean),
      estimatedImageGenerationTime: enhancedChapters.length * 45, // seconds
      nextStep: 'image_generation'
    }
  };
};

module.exports = async function (input) {
  const chapter = input.json;
  const style = chapter.style || 'documentary';

  // Style-specific prompt enhancements
  const styleEnhancers = {
    cinematic: `Cinematic film still, dramatic lighting, shallow depth of field, 35mm film grain, Academy ratio, `,
    documentary: `Documentary photography, authentic lighting, realistic details, journalistic style, `,
    painting: `Oil painting style, visible brush strokes, rich textures, classical composition, `,
    infographic: `Clear infographic style, labeled elements, flat colors, diagrammatic, educational, `
  };

  // Enhance prompt based on style
  const enhancedPrompt = `${styleEnhancers[style] || ''}${chapter.image_prompt}. ` +
    `Historical accuracy is crucial. ` +
    `The text "${chapter.date}" should be naturally integrated into the scene. ` +
    `High resolution, detailed, professional quality.`;

  // Determine model based on style
  const model = style === 'cinematic' ? 'nano-banana-pro-premium' : 
                style === 'painting' ? 'nano-banana-pro-art' : 
                'nano-banana-pro';

  return {
    ...chapter,
    enhanced_image_prompt: enhancedPrompt,
    target_model: model,
    generation_params: {
      aspect_ratio: "16:9",
      resolution: style === 'cinematic' ? "2K" : "1K",
      style_preset: style,
      guidance_scale: 7.5,
      steps: 30
    },
    timestamp: new Date().toISOString()
  };
};

module.exports = async function (input) {
  const item = input.json;

  // Check if we should retry
  const attempts = item.image_generation_attempts || 0;

  if (attempts >= 3) {
    return {
      ...item,
      image_status: 'failed',
      image_generation_attempts: attempts,
      error: 'Max retries exceeded'
    };
  }

  // Wait before retry (exponential backoff)
  const waitTime = Math.min(30 * Math.pow(2, attempts), 300);

  return {
    wait: waitTime,
    retry_item: {
      ...item,
      image_generation_attempts: attempts + 1,
      image_status: 'retrying'
    }
  };
};

module.exports = async function (input) {
  const response = input.json;
  const item = input.item.json;

  return {
    ...item,
    image_status: 'completed',
    image_url: response.secure_url,
    image_public_id: response.public_id,
    image_format: response.format,
    image_dimensions: `${response.width}x${response.height}`,
    uploaded_at: new Date().toISOString()
  };
};

module.exports = async function (input) {
  const items = input.json;
  const jobData = items[0]?.jobData || {};

  // Group by job_id
  const grouped = {};
  items.forEach(item => {
    if (!grouped[item.job_id]) {
      grouped[item.job_id] = {
        jobData: item.jobData,
        chapters: []
      };
    }
    grouped[item.job_id].chapters.push(item);
  });

  // Sort chapters by chapter_id
  Object.values(grouped).forEach(group => {
    group.chapters.sort((a, b) => a.chapter_id - b.chapter_id);
  });

  return Object.values(grouped);
};

module.exports = async function (input) {
  const { jobData, chapters } = input.json;
  const style = jobData.style || 'documentary';
  const language = jobData.language || 'en';

  // Get template based on style
  const templates = {
    cinematic: getCinematicTemplate,
    documentary: getDocumentaryTemplate,
    painting: getArtisticTemplate,
    infographic: getInfographicTemplate
  };

  const templateFunction = templates[style] || getDocumentaryTemplate;
  const html = templateFunction(jobData, chapters, language);

  return {
    ...input.json,
    html_content: html,
    template_used: style,
    page_count: chapters.length,
    generated_at: new Date().toISOString()
  };
};

