module.exports = async function (input) {
  const { jobData, webViewLink } = input.json;
  const source = jobData.source;

  // Format completion message based on source
  const messages = {
    telegram: {
      text: `✅ *Your history book is ready!*\n\n📚 **${jobData.topic}**\n📄 ${jobData.metadata.estimatedChapters} pages\n⏱️ Generated in ${Math.round((new Date() - new Date(jobData.createdAt)) / 60000)} minutes\n🔗 [Download PDF](${webViewLink})\n\n_Keep history alive with CODEX AI_`,
      parse_mode: 'Markdown'
    },
    discord: {
      content: `📚 **${jobData.topic}** is ready!\nGenerated ${jobData.metadata.estimatedChapters} pages in ${Math.round((new Date() - new Date(jobData.createdAt)) / 60000)} minutes\n🔗 Download: ${webViewLink}\n\n*Powered by CODEX AI Historian*`
    },
    web: {
      text: `Your book "${jobData.topic}" is complete! Download: ${webViewLink}`,
      sessionId: jobData.metadata.sessionId
    }
  };

  const response = messages[source] || messages.telegram;

  return {
    source: source,
    recipient: jobData.metadata.chatId || jobData.metadata.channelId || jobData.metadata.sessionId,
    message: response,
    jobData: jobData,
    pdfUrl: webViewLink,
    timestamp: new Date().toISOString()
  };
};

